"use client"

import { useState, useEffect } from "react"
import { useRouter } from "next/navigation"
import { useAuthStore } from "@/store/auth-store"
import { PageHeader } from "@/components/shared/page-header"
import { EntityStatusBadge } from "@/components/shared/status-badge"
import { ConfirmDialog } from "@/components/shared/confirm-dialog"
import { Card, CardContent } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Badge } from "@/components/ui/badge"
import { Textarea } from "@/components/ui/textarea"
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from "@/components/ui/dialog"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu"
import {
  MoreHorizontal,
  Pencil,
  Trash2,
  Search,
  UserCog,
  Users,
  GitBranch,
  FileText,
  Crown,
  Settings,
  Loader2,
} from "lucide-react"
import { toast } from "sonner"

// Types
interface Branch {
  id: string
  name: string
  dmaId: string
  utilityId: string
}

interface Engineer {
  id: string
  name: string
  email: string
  role: string
  status: string
}

interface Team {
  id: string
  name: string
  description: string | null
  branchId: string
  branchName: string
  dmaId: string
  dmaName: string
  utilityId: string
  leaderId: string | null
  leaderName?: string
  status: "active" | "inactive"
  memberCount: number
  activeReports: number
  engineerIds: string[]
  createdAt: string
  updatedAt: string
}

export default function TeamsPage() {
  const router = useRouter()
  const { currentUser } = useAuthStore()
  
  // Data states
  const [teams, setTeams] = useState<Team[]>([])
  const [branches, setBranches] = useState<Branch[]>([])
  const [loading, setLoading] = useState(true)
  
  // UI states
  const [search, setSearch] = useState("")
  const [dialogOpen, setDialogOpen] = useState(false)
  const [editingTeam, setEditingTeam] = useState<Team | null>(null)
  const [deleteId, setDeleteId] = useState<string | null>(null)
  const [saving, setSaving] = useState(false)
  
  // Form states
  const [formName, setFormName] = useState("")
  const [formDescription, setFormDescription] = useState("")
  const [formBranchId, setFormBranchId] = useState("")
  const [formStatus, setFormStatus] = useState<"active" | "inactive">("active")

  // Only DMA managers can access this page
  const isDMAManager = currentUser?.role === "dma_manager"
  const dmaId = currentUser?.dmaId ?? ""
  const utilityId = currentUser?.utilityId ?? ""

  // Fetch teams and branches on mount
  useEffect(() => {
    if (!isDMAManager || !dmaId) return
    
    async function fetchData() {
      try {
        setLoading(true)
        
        // Fetch teams for this DMA
        const teamsRes = await fetch(`/api/teams?dmaId=${dmaId}`)
        if (teamsRes.ok) {
          const teamsData = await teamsRes.json()
          setTeams(teamsData)
        }
        
        // Fetch branches for this DMA
        const branchesRes = await fetch(`/api/branches?dmaId=${dmaId}`)
        if (branchesRes.ok) {
          const branchesData = await branchesRes.json()
          setBranches(branchesData)
        }
      } catch (error) {
        console.error("Error fetching data:", error)
        toast.error("Failed to load data")
      } finally {
        setLoading(false)
      }
    }
    
    fetchData()
  }, [isDMAManager, dmaId])

  // Redirect non-DMA managers
  if (!isDMAManager) {
    return (
      <div className="flex flex-col gap-6">
        <PageHeader
          title="Teams Management"
          description="Only DMA Managers can manage teams"
        />
        <Card>
          <CardContent className="py-12 text-center text-muted-foreground">
            You do not have permission to access this page. Only DMA Managers can manage teams.
          </CardContent>
        </Card>
      </div>
    )
  }

  // Filter teams by search
  const filteredTeams = teams.filter(
    (t) =>
      t.name.toLowerCase().includes(search.toLowerCase()) ||
      t.branchName.toLowerCase().includes(search.toLowerCase()) ||
      (t.leaderName?.toLowerCase().includes(search.toLowerCase()) ?? false)
  )

  function openCreateDialog() {
    setEditingTeam(null)
    setFormName("")
    setFormDescription("")
    setFormBranchId("")
    setFormStatus("active")
    setDialogOpen(true)
  }

  function openEditDialog(team: Team) {
    setEditingTeam(team)
    setFormName(team.name)
    setFormDescription(team.description || "")
    setFormBranchId(team.branchId)
    setFormStatus(team.status)
    setDialogOpen(true)
  }

  async function handleSubmit() {
    if (!formName.trim()) {
      toast.error("Team name is required")
      return
    }
    if (!formBranchId) {
      toast.error("Please select a branch")
      return
    }

    setSaving(true)
    
    try {
      const payload = {
        name: formName.trim(),
        description: formDescription.trim() || null,
        branchId: formBranchId,
        dmaId: dmaId,
        status: formStatus,
      }

      let response: Response
      
      if (editingTeam) {
        response = await fetch("/api/teams", {
          method: "PUT",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ id: editingTeam.id, ...payload }),
        })
      } else {
        response = await fetch("/api/teams", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(payload),
        })
      }

      if (response.ok) {
        const savedTeam = await response.json()
        
        if (editingTeam) {
          setTeams((prev) => prev.map((t) => (t.id === savedTeam.id ? savedTeam : t)))
          toast.success("Team updated successfully")
        } else {
          setTeams((prev) => [...prev, savedTeam])
          toast.success("Team created successfully")
        }
        
        setDialogOpen(false)
      } else {
        const error = await response.json()
        toast.error(error.error || "Failed to save team")
      }
    } catch (error) {
      console.error("Error saving team:", error)
      toast.error("Failed to save team")
    } finally {
      setSaving(false)
    }
  }

  async function handleDelete() {
    if (!deleteId) return
    
    try {
      const response = await fetch(`/api/teams?id=${deleteId}`, {
        method: "DELETE",
      })
      
      if (response.ok) {
        setTeams((prev) => prev.filter((t) => t.id !== deleteId))
        toast.success("Team deleted successfully")
        setDeleteId(null)
      } else {
        const error = await response.json()
        toast.error(error.error || "Failed to delete team")
      }
    } catch (error) {
      console.error("Error deleting team:", error)
      toast.error("Failed to delete team")
    }
  }

  function navigateToManageTeam(teamId: string) {
    router.push(`/teams/${teamId}`)
  }

  if (loading) {
    return (
      <div className="flex flex-col gap-6">
        <PageHeader
          title="Team Management"
          description="Create and manage teams within your DMA"
        />
        <Card>
          <CardContent className="flex items-center justify-center py-12">
            <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
          </CardContent>
        </Card>
      </div>
    )
  }

  return (
    <div className="flex flex-col gap-6">
      <PageHeader
        title="Team Management"
        description="Create and manage teams within your DMA"
        actionLabel="Create Team"
        actionIcon={UserCog}
        onAction={openCreateDialog}
      />

      {/* Search */}
      <div className="relative max-w-sm">
        <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
        <Input
          placeholder="Search teams..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className="pl-9"
        />
      </div>

      {/* Info Banner */}
      <Card className="border-blue-200 bg-blue-50 dark:border-blue-900 dark:bg-blue-950">
        <CardContent className="flex items-center gap-3 py-3">
          <Settings className="h-5 w-5 text-blue-600" />
          <p className="text-sm text-blue-700 dark:text-blue-300">
            Create teams with basic info first, then use "Manage Team" to assign members and team leaders.
          </p>
        </CardContent>
      </Card>

      {/* Team cards grid */}
      {filteredTeams.length === 0 ? (
        <Card>
          <CardContent className="flex flex-col items-center justify-center py-12">
            <UserCog className="h-12 w-12 text-muted-foreground/30" />
            <p className="mt-3 text-sm text-muted-foreground">
              {search ? "No teams match your search" : "No teams created yet. Create your first team to get started."}
            </p>
          </CardContent>
        </Card>
      ) : (
        <div className="grid grid-cols-1 gap-4 md:grid-cols-2 xl:grid-cols-3">
          {filteredTeams.map((team) => (
            <Card
              key={team.id}
              className="transition-all duration-200 hover:shadow-md hover:-translate-y-0.5"
            >
              <CardContent className="p-5">
                <div className="flex items-start justify-between">
                  <div className="flex items-center gap-3">
                    <div className="flex h-10 w-10 items-center justify-center rounded-xl bg-primary/10">
                      <UserCog className="h-5 w-5 text-primary" />
                    </div>
                    <div>
                      <h3 className="text-sm font-semibold">{team.name}</h3>
                      <div className="flex items-center gap-1.5 text-xs text-muted-foreground">
                        <GitBranch className="h-3 w-3" />
                        {team.branchName}
                      </div>
                    </div>
                  </div>
                  <DropdownMenu>
                    <DropdownMenuTrigger asChild>
                      <Button
                        variant="ghost"
                        size="icon"
                        className="h-8 w-8"
                      >
                        <MoreHorizontal className="h-4 w-4" />
                      </Button>
                    </DropdownMenuTrigger>
                    <DropdownMenuContent align="end">
                      <DropdownMenuItem
                        onClick={() => navigateToManageTeam(team.id)}
                      >
                        <Settings className="mr-2 h-4 w-4" />
                        Manage Team
                      </DropdownMenuItem>
                      <DropdownMenuItem
                        onClick={() => openEditDialog(team)}
                      >
                        <Pencil className="mr-2 h-4 w-4" />
                        Edit Info
                      </DropdownMenuItem>
                      <DropdownMenuItem
                        onClick={() => setDeleteId(team.id)}
                        className="text-red-600 focus:text-red-600"
                      >
                        <Trash2 className="mr-2 h-4 w-4" />
                        Delete
                      </DropdownMenuItem>
                    </DropdownMenuContent>
                  </DropdownMenu>
                </div>

                {team.description && (
                  <p className="mt-2 text-xs text-muted-foreground line-clamp-2">
                    {team.description}
                  </p>
                )}

                <div className="mt-4 flex items-center gap-1.5">
                  {team.leaderName ? (
                    <>
                      <Crown className="h-3.5 w-3.5 text-amber-500" />
                      <span className="text-xs font-medium">
                        {team.leaderName}
                      </span>
                    </>
                  ) : (
                    <span className="text-xs text-muted-foreground italic">
                      No leader assigned
                    </span>
                  )}
                  <EntityStatusBadge status={team.status} />
                </div>

                <div className="mt-3 flex items-center gap-4 text-xs text-muted-foreground">
                  <div className="flex items-center gap-1">
                    <Users className="h-3 w-3" />
                    {team.memberCount} members
                  </div>
                  <div className="flex items-center gap-1">
                    <FileText className="h-3 w-3" />
                    {team.activeReports} active reports
                  </div>
                </div>

                {/* Manage Team Button */}
                <Button
                  variant="outline"
                  size="sm"
                  className="mt-4 w-full"
                  onClick={() => navigateToManageTeam(team.id)}
                >
                  <Settings className="mr-2 h-4 w-4" />
                  Manage Team Members
                </Button>
              </CardContent>
            </Card>
          ))}
        </div>
      )}

      {/* Create/Edit Dialog */}
      <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
        <DialogContent className="max-w-md">
          <DialogHeader>
            <DialogTitle>
              {editingTeam ? "Edit Team Info" : "Create New Team"}
            </DialogTitle>
          </DialogHeader>
          <div className="flex flex-col gap-4 py-4">
            <div className="flex flex-col gap-2">
              <Label htmlFor="team-name">Team Name *</Label>
              <Input
                id="team-name"
                value={formName}
                onChange={(e) => setFormName(e.target.value)}
                placeholder="e.g., Team Alpha"
              />
            </div>
            
            <div className="flex flex-col gap-2">
              <Label htmlFor="team-description">Description (Optional)</Label>
              <Textarea
                id="team-description"
                value={formDescription}
                onChange={(e) => setFormDescription(e.target.value)}
                placeholder="Brief description of this team's responsibilities..."
                rows={3}
              />
            </div>
            
            <div className="flex flex-col gap-2">
              <Label>Utility</Label>
              <Input
                value="Auto-assigned from your profile"
                disabled
                className="bg-muted"
              />
            </div>
            
            <div className="flex flex-col gap-2">
              <Label>DMA</Label>
              <Input
                value="Auto-assigned from your profile"
                disabled
                className="bg-muted"
              />
            </div>
            
            <div className="flex flex-col gap-2">
              <Label>Branch *</Label>
              <Select
                value={formBranchId}
                onValueChange={setFormBranchId}
              >
                <SelectTrigger>
                  <SelectValue placeholder="Select branch" />
                </SelectTrigger>
                <SelectContent>
                  {branches.map((b) => (
                    <SelectItem key={b.id} value={b.id}>
                      {b.name}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            
            <div className="flex flex-col gap-2">
              <Label>Status</Label>
              <Select
                value={formStatus}
                onValueChange={(v) => setFormStatus(v as "active" | "inactive")}
              >
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="active">Active</SelectItem>
                  <SelectItem value="inactive">Inactive</SelectItem>
                </SelectContent>
              </Select>
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setDialogOpen(false)}>
              Cancel
            </Button>
            <Button onClick={handleSubmit} disabled={saving}>
              {saving && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              {editingTeam ? "Save Changes" : "Create Team"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Delete Confirmation */}
      <ConfirmDialog
        open={!!deleteId}
        onOpenChange={() => setDeleteId(null)}
        title="Delete Team"
        description="Are you sure you want to delete this team? All team members will be unassigned. This action cannot be undone."
        confirmLabel="Delete Team"
        onConfirm={handleDelete}
      />
    </div>
  )
}